# compare_golden.py
# Compare pre-patch and post-patch golden prompt outputs

import json, sys
from typing import Optional

def compare_golden(before_path: str, after_path: str,
                   max_latency_increase_pct: float = 10.0) -> bool:
    with open(before_path) as f: before = {r["id"]: r for r in json.load(f)}
    with open(after_path) as f:  after  = {r["id"]: r for r in json.load(f)}

    changed_outputs = []
    latency_regressions = []

    for pid, pre in before.items():
        post = after.get(pid)
        if not post:
            print(f"MISSING in post-patch run: {pid}")
            continue

        if pre["response_hash"] != post["response_hash"]:
            changed_outputs.append({
                "id": pid,
                "category": pre["category"],
                "before": pre["response"][:150],
                "after":  post["response"][:150],
            })

        latency_delta_pct = ((post["latency_ms"] - pre["latency_ms"])
                             / pre["latency_ms"]) * 100
        if latency_delta_pct > max_latency_increase_pct:
            latency_regressions.append({
                "id": pid,
                "before_ms": pre["latency_ms"],
                "after_ms": post["latency_ms"],
                "increase_pct": round(latency_delta_pct, 1),
            })

    if changed_outputs:
        print(f"\n⚠ {len(changed_outputs)} output(s) changed — HUMAN REVIEW REQUIRED:")
        for item in changed_outputs[:5]:  # show first 5
            print(f"  [{item['category']}] {item['id']}")
            print(f"    Before: {item['before']}")
            print(f"    After:  {item['after']}")
        if len(changed_outputs) > 5:
            print(f"  ... and {len(changed_outputs)-5} more")

    if latency_regressions:
        print(f"\n⚠ {len(latency_regressions)} latency regression(s):")
        for item in latency_regressions:
            print(f"  {item['id']}: {item['before_ms']}ms → {item['after_ms']}ms (+{item['increase_pct']}%)")

    # Return True only if no changes AND no latency regressions
    # Changed outputs require human review but do not auto-block
    clean = len(latency_regressions) == 0
    if changed_outputs and clean:
        print("\nNote: output changes detected but no latency regression. Manual review needed.")
        sys.exit(2)  # exit 2 = human gate required
    return clean

if __name__ == "__main__":
    ok = compare_golden(sys.argv[1], sys.argv[2])
    sys.exit(0 if ok else 1)
